import re, os, subprocess, itertools, sys

PRE=r'''\documentclass[letterpaper]{article}
\setlength{\topmargin}{2in}
\setlength{\headheight}{0pt}
\setlength{\headsep}{0pt}
\setlength{\textheight}{5in}
\setlength{\textwidth}{2.5in}
\setlength{\oddsidemargin}{2in}
\setlength{\evensidemargin}{2in}
\setlength{\footskip}{0.5in}
\begin{document}
'''
POST='\n\\end{document}\n'

fams={}
for line in open('/app/synonyms.txt'):
    line=line.strip()
    if not line: continue
    words=[w.strip() for w in line.split(',')]
    fams[words[0]]=words

paras=[p for p in open('/app/input.tex').read().split('\n') if p.strip()]

WD='/tmp/tw'
os.makedirs(WD,exist_ok=True)

def overfull(text):
    with open(WD+'/t.tex','w') as f:
        f.write(PRE+text+POST)
    subprocess.run(['pdflatex','-interaction=nonstopmode','t.tex'],cwd=WD,
                   stdout=subprocess.DEVNULL,stderr=subprocess.DEVNULL)
    log=open(WD+'/t.log').read()
    return [float(m) for m in re.findall(r'Overfull \\hbox \(([\d.]+)pt too wide\)',log)]

def occurrences(text):
    occ=[]  # (start,end,word,alts)
    for key,words in fams.items():
        for m in re.finditer(r'(?<![A-Za-z])'+re.escape(key)+r'(?![A-Za-z])',text):
            alts=[w for w in words if w!=key]
            occ.append((m.start(),m.end(),key,alts))
    occ.sort()
    return occ

def apply_subs(text, occ, choice):
    # choice: dict index->replacement word
    out=[]; last=0
    for i,(s,e,w,alts) in enumerate(occ):
        out.append(text[last:s])
        out.append(choice.get(i,w))
        last=e
    out.append(text[last:])
    return ''.join(out)

def solve(pidx):
    text=paras[pidx]
    base=overfull(text)
    print(f"para {pidx}: base overfull {base}")
    if not base: 
        return text
    occ=occurrences(text)
    print(f"  {len(occ)} replaceable occurrences")
    # try singles
    for i,(s,e,w,alts) in enumerate(occ):
        for a in alts:
            nt=apply_subs(text,occ,{i:a})
            ov=overfull(nt)
            if not ov:
                print(f"  SINGLE fix: {w}->{a}")
                return nt
    # try pairs
    n=len(occ)
    for i in range(n):
        for a in occ[i][3]:
            for j in range(i+1,n):
                for b in occ[j][3]:
                    nt=apply_subs(text,occ,{i:a,j:b})
                    ov=overfull(nt)
                    if not ov:
                        print(f"  PAIR fix: {occ[i][2]}->{a}, {occ[j][2]}->{b}")
                        return nt
    print("  NO fix found (single/pair)")
    return None

targets=[int(x) for x in sys.argv[1:]] or [2,3,6,9]
res={}
for p in targets:
    res[p]=solve(p)
import json
open('/tmp/res.json','w').write(json.dumps({str(k):v for k,v in res.items()}))
